-- Custom item queries
-- Create/Get/List are auto-generated by pgtempl (CreateDefaultItem / GetItem / ListItem).

-- name: ListItemsByPaymentSession :many
SELECT * FROM "order"."item" WHERE "payment_session_id" = @payment_session_id;

-- name: ListSellerPendingItems :many
-- Only items whose payment session has succeeded — sellers should not see items
-- still awaiting buyer payment or whose session has failed.
SELECT i.* FROM "order"."item" i
JOIN "order"."payment_session" ps ON ps."id" = i."payment_session_id"
WHERE i."seller_id" = @seller_id
  AND i."order_id" IS NULL
  AND i."date_cancelled" IS NULL
  AND ps."status" = 'Success'
ORDER BY i."date_created" DESC;

-- name: CountSellerPendingItems :one
SELECT COUNT(*) FROM "order"."item" i
JOIN "order"."payment_session" ps ON ps."id" = i."payment_session_id"
WHERE i."seller_id" = @seller_id
  AND i."order_id" IS NULL
  AND i."date_cancelled" IS NULL
  AND ps."status" = 'Success';

-- name: ListBuyerPendingItems :many
SELECT * FROM "order"."item"
WHERE "account_id" = @account_id
  AND "order_id" IS NULL
  AND "date_cancelled" IS NULL
ORDER BY "date_created" DESC;

-- name: CountBuyerPendingItems :one
SELECT COUNT(*) FROM "order"."item"
WHERE "account_id" = @account_id
  AND "order_id" IS NULL
  AND "date_cancelled" IS NULL;

-- name: ListPendingPaymentItemsByPaymentSession :many
SELECT * FROM "order"."item"
WHERE "payment_session_id" = @payment_session_id
  AND "order_id" IS NULL
  AND "date_cancelled" IS NULL;

-- name: SetItemsOrderID :exec
UPDATE "order"."item"
SET "order_id" = @order_id
WHERE "id" = ANY(@item_ids::BIGINT[]) AND "order_id" IS NULL;

-- name: UnlinkItemsFromOrder :exec
UPDATE "order"."item"
SET "order_id" = NULL
WHERE "order_id" = @order_id;

-- name: CancelItem :one
-- Marks item cancelled. The compensating refund transaction (negative amount,
-- reverses_id pointing to the original payment tx) is inserted separately by biz code.
UPDATE "order"."item"
SET "date_cancelled" = CURRENT_TIMESTAMP,
    "cancelled_by_id" = @cancelled_by_id
WHERE "id" = @id AND "date_cancelled" IS NULL
RETURNING *;

-- name: CancelItemsByIDs :execrows
UPDATE "order"."item"
SET "date_cancelled" = CURRENT_TIMESTAMP
WHERE "id" = ANY(@item_ids::BIGINT[])
  AND "order_id" IS NULL
  AND "date_cancelled" IS NULL;

-- name: SumTotalAmountByOrder :one
SELECT COALESCE(SUM("total_amount"), 0)::BIGINT AS total
FROM "order"."item"
WHERE "order_id" = @order_id AND "date_cancelled" IS NULL;
